#include <stdio.h>
#include <omp.h>

#define N 1000000

int main() {
 int i;

 // =========================================================================
 // PATTERN 1: PARALLELIZABLE - No loop-carried dependency
 // =========================================================================
 printf("=== Pattern 1: Parallelizable (Element-wise Square) ===\n")

 float a[N], b[N];
 for (i = 0; i < N; i++) {
 a[i] = (float)i;
 }

 // SAFE: Each iteration writes to b[i], reads from a[i]
 // No overlap between iterations - completely independent
 #pragma omp parallel for
 for (i = 0; i < N; i++) {
 b[i] = a[i] * a[i];
 }

 printf("First 5 results: ");
 for (i = 0; i < 5; i++) printf("%.0f ", b[i]);
 printf("\n");

 // =========================================================================
 // PATTERN 2: FLOW DEPENDENCY - NOT safe to parallelize
 // =========================================================================
 printf("\n=== Pattern 2: Flow Dependency (Prefix Sum) ===\n");

 float c[N];
 for (i = 0; i < N; i++) {
 c[i] = 1.0f;
 }

 // UNSAFE: Iteration i depends on c[i-1] from previous iteration
 // If we uncomment the parallel directive, we get WRONG results
 // The dependency chain: c[1] = c[1] + c[0], c[2] = c[2] + c[1], etc.

 // Sequential version (correct):
 for (i = 1; i < N; i++) {
 c[i] = c[i] + c[i-1]; // Flow dependency: reads previous write
 }

 printf("First 10 prefix sums: ");
 for (i = 0; i < 10; i++) printf("%.0f ", c[i]);
 printf("\n");
 printf("Note: If parallelized incorrectly, results would be incorrect.\n");

 // =========================================================================
 // PATTERN 3: OUTPUT DEPENDENCY - Fixed with reduction clause
 // =========================================================================
 printf("\n=== Pattern 3: Output Dependency (Sum with Reduction) ===\n");

 float arr[N];
 float sum = 0.0f;

 for (i = 0; i < N; i++) {
 arr[i] = 1.0f;
 }

 // UNSAFE without reduction: Multiple threads read-modify-write 'sum'
 // #pragma omp parallel for // WRONG: Race condition on 'sum'
 // for (i = 0; i < N; i++) {
 // sum += arr[i]; // Read-modify-write on shared variable
 // }

 // SAFE with reduction: Each thread has private copy, then combine
 #pragma omp parallel for reduction(+:sum)
 for (i = 0; i < N; i++) {
 sum += arr[i]; // Thread-private 'sum' gets combined at end
 }

 printf("Sum of %d ones: %.0f\n", N, sum);

 // =========================================================================
 // PATTERN 4: ANTI-DEPENDENCY - More complex example
 // =========================================================================
 printf("\n=== Pattern 4: Anti-Dependency ===\n");

 float x[N], y[N];
 for (i = 0; i < N; i++) {
 x[i] = (float)i;
 y[i] = 0.0f;
 }

 // This is harder to visualize but exists: iteration i reads y[i]
 // which might be written by iteration i+1 (future iteration)
 // Sequential (correct):
 for (i = 0; i < N - 1; i++) {
 float temp = y[i]; // Read y[i]
 y[i + 1] = temp + 2.0f; // Write to y[i+1] in future iteration
 }

 printf("First 5 y values after anti-dependency pattern: ");
 for (i = 0; i < 5; i++) printf("%.0f ", y[i]);
 printf("\n");

 // =========================================================================
 // PATTERN 5: WRONG solution - using atomic (inefficient)
 // =========================================================================
 printf("\n=== Pattern 5: Why 'atomic' is inefficient ===\n");

 sum = 0.0f;

 // CORRECT but VERY SLOW: Synchronizes every iteration
 double start = omp_get_wtime();
 #pragma omp parallel for
 for (i = 0; i < N; i++) {
 #pragma omp atomic
 sum += arr[i];
 }
 double end = omp_get_wtime();

 printf("Sum with atomic: %.0f (time: %.4f seconds)\n", sum, end - start);
 printf("Note: 'atomic' synchronizes every update - destroys parallelism!\n");

 printf("\n=== Summary ===\n");
 printf("1. Pattern 1: SAFE - No dependencies between iterations\n");
 printf("2. Pattern 2: UNSAFE - Flow dependency (sequential required)\n");
 printf("3. Pattern 3: FIXED - Use 'reduction' clause for accumulations\n");
 printf("4. Pattern 5: AVOID - atomic kills performance\n");

 return 0;
}
